if (SceneManager._scene && SceneManager._scene._actorWindow && SceneManager._scene._actorWindow.active) return false;
return true;

try {
    const actor = $gameActors.actor(6);
    const scene = SceneManager._scene;

    if (!$gameParty.inBattle() || !actor || !$gameParty.battleMembers().includes(actor)) return false;
